    let result = match rbtdre_run_single_case(case, &colors, &roots.trace_root) {
        Ok(r) => r,
        Err(msg) => rbtd::rbtdrg_fatal_now!("rbtd: case execution error: {}", msg),
    };

    rbtdre_print_summary(&result, &colors);

    if result.failed > 0 {
        ExitCode::FAILURE
    } else {
        ExitCode::SUCCESS
    }
}

