        for line in &rewritten {
            writeln!(tmp, "{}", line)
                .map_err(|e| format!("write tmp rbrv.env for {}: {}", vessel_dir, e))?;
        }
    }
    std::fs::rename(&tmp_path, &rbrv_path)
